"""Generate runtime and CI requirements from pyproject dependency declarations."""

from __future__ import annotations

import argparse
import sys
from pathlib import Path

try:
    import tomllib
except ModuleNotFoundError as exc:  # pragma: no cover
    raise RuntimeError("Python 3.11+ is required to parse pyproject.toml") from exc


PYPROJECT_PATH = Path("pyproject.toml")
RUNTIME_REQUIREMENTS_PATH = Path("requirements.txt")
CI_REQUIREMENTS_PATH = Path("requirements-ci.txt")
RUNTIME_HEADER_LINES = (
    "# This file is generated from pyproject.toml project dependencies.",
    "# Regenerate with: python scripts/generate_requirements.py",
    "# Do not edit this file manually.",
)
CI_HEADER_LINES = (
    "# This file is generated from pyproject.toml runtime and optional dependencies.",
    "# Regenerate with: python scripts/generate_requirements.py",
    "# Do not edit this file manually.",
)


class RequirementsGenerationError(RuntimeError):
    """Raised when requirement generation cannot proceed."""


def _load_dependencies(pyproject_path: Path) -> tuple[list[str], list[str]]:
    """Return runtime and CI dependency specifiers from ``pyproject.toml``.

    The CI requirements intentionally include every optional dependency group so
    that validation environments can install the full toolchain from one generated
    file while production installs stay on the slimmer runtime set.
    """
    if not pyproject_path.exists():
        raise FileNotFoundError(f"Missing dependency source file: {pyproject_path}")

    data = tomllib.loads(pyproject_path.read_text(encoding="utf-8"))
    project_data = data.get("project")
    if not isinstance(project_data, dict):
        raise RequirementsGenerationError("Missing [project] section in pyproject.toml")

    runtime_dependencies = project_data.get("dependencies")
    if not isinstance(runtime_dependencies, list):
        raise RequirementsGenerationError(
            "Expected [project].dependencies to be a list of requirement specifiers"
        )

    optional_dependencies = project_data.get("optional-dependencies", {})
    if not isinstance(optional_dependencies, dict):
        raise RequirementsGenerationError(
            "Expected [project.optional-dependencies] to be a table of dependency lists"
        )

    ci_optional_dependencies: list[str] = []
    for group_name, group_dependencies in optional_dependencies.items():
        if not isinstance(group_dependencies, list):
            raise RequirementsGenerationError(
                f"Expected [project.optional-dependencies].{group_name} to be a list"
            )
        ci_optional_dependencies.extend(group_dependencies)

    ci_dependencies = [*runtime_dependencies, *ci_optional_dependencies]
    dependencies = ci_dependencies

    invalid_entries = [entry for entry in dependencies if not isinstance(entry, str)]
    if invalid_entries:
        raise RequirementsGenerationError("Found non-string dependency entries in pyproject.toml")

    return runtime_dependencies, ci_dependencies


def _build_requirements_text(dependencies: list[str], header_lines: tuple[str, ...]) -> str:
    """Build normalized requirements content with generation metadata."""
    lines = [*header_lines, "", *sorted(set(dependencies), key=str.lower)]
    return "\n".join(lines) + "\n"


def generate_requirements(
    pyproject_path: Path,
    runtime_requirements_path: Path,
    ci_requirements_path: Path,
) -> None:
    """Write runtime and CI requirements files from ``pyproject.toml``."""
    runtime_dependencies, ci_dependencies = _load_dependencies(pyproject_path)
    runtime_requirements_path.write_text(
        _build_requirements_text(runtime_dependencies, RUNTIME_HEADER_LINES),
        encoding="utf-8",
    )
    ci_requirements_path.write_text(
        _build_requirements_text(ci_dependencies, CI_HEADER_LINES),
        encoding="utf-8",
    )


def check_requirements(
    pyproject_path: Path,
    runtime_requirements_path: Path,
    ci_requirements_path: Path,
) -> bool:
    """Return whether committed requirements content matches generated output."""
    runtime_dependencies, ci_dependencies = _load_dependencies(pyproject_path)
    expected_runtime = _build_requirements_text(runtime_dependencies, RUNTIME_HEADER_LINES)
    expected_ci = _build_requirements_text(ci_dependencies, CI_HEADER_LINES)

    current_runtime = (
        runtime_requirements_path.read_text(encoding="utf-8")
        if runtime_requirements_path.exists()
        else ""
    )
    current_ci = (
        ci_requirements_path.read_text(encoding="utf-8")
        if ci_requirements_path.exists()
        else ""
    )
    return current_runtime == expected_runtime and current_ci == expected_ci


def main() -> int:
    """Parse CLI arguments and generate or validate requirements output."""
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "--check",
        action="store_true",
        help="Verify requirements files match generated output without writing files.",
    )
    args = parser.parse_args()

    if args.check:
        if check_requirements(PYPROJECT_PATH, RUNTIME_REQUIREMENTS_PATH, CI_REQUIREMENTS_PATH):
            print("requirements.txt and requirements-ci.txt are up to date")
            return 0
        print(
            "requirements files are out of date. "
            "Run: python scripts/generate_requirements.py",
            file=sys.stderr,
        )
        return 1

    generate_requirements(PYPROJECT_PATH, RUNTIME_REQUIREMENTS_PATH, CI_REQUIREMENTS_PATH)
    print("Regenerated requirements.txt and requirements-ci.txt from pyproject.toml")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
